    if (session == NULL || route == NULL) {
        return;
    }

    replacement = malloc(strlen(route) + 1);
    if (replacement == NULL) {
        return;
    }

    strcpy(replacement, route);
    session->cached_route = replacement;
}

char **build_retry_batch(int count, int fail_index) {
