    if (batch == NULL) {
        return NULL;
    }

    for (int i = 0; i < count; ++i) {
        batch[i] = malloc(48);
        if (batch[i] == NULL) {
            return NULL;
        }
        snprintf(batch[i], 48, "retry-step-%d", i);
        if (i == fail_index) {
            return NULL;
        }
    }

    return batch;
}

void session_close_buggy(Session *session) {
    if (session == NULL) {
        return;
    }

    free(session->name);
    free(session->cached_route);
    free(session);
}
